/**
 * Boundary-safe cut index for keep-last-N compaction. Returns the index s such that messages.slice(s) is the verbatim tail to keep. Never cuts INSIDE a tool_use/tool_result pair: if the cut would land on a 'tool' role message, it walks back to include the assistant message that issued the tool_calls (Anthropic/OpenAI both reject a tool result whose call is missing from the request). minStart = first compactable index (1 when messages[0] is the system prompt).
 */
// @kern-source: compaction:19
export function findSafeKeepStart(messages: CompactMessage[], targetKeep: number, minStart: number): number {
  const len = Array.isArray(messages) ? messages.length : 0;
  if (len === 0) return 0;
  const floor = Math.max(0, Math.min(minStart, len));
  let s = Math.max(floor, len - Math.max(1, Math.floor(targetKeep)));
  // Walk back over tool results so the kept tail starts at the assistant
  // message that owns them (or at the floor).
  while (s > floor && s < len && (messages[s] as any)?.role === 'tool') s--;
  return s;
}

