/**
 * Render the carried-forward WorkingSet as a compact, SINGLE-line block for the compaction message. Empty string when there's nothing to carry (absent/empty WorkingSet) so renderCompactionText drops it via the .filter(Boolean). Shape: a 'WORKING SET:' prefix followed by the present segments — files (first few + '(+N more)'), verifier status, and recent hypotheses — concatenated on ONE line joined by ' | '.
 */
// @kern-source: compaction:181
export function renderWorkingSet(ws: WorkingSet|null): string {
  if (!ws) return '';
  const parts: string[] = [];
  if (Array.isArray(ws.filesInPlay) && ws.filesInPlay.length > 0) {
    const shown = ws.filesInPlay.slice(0, 5);
    const more = ws.filesInPlay.length - shown.length;
    parts.push(`files: ${shown.join(', ')}${more > 0 ? ` (+${more} more)` : ''}`);
  }
  if (typeof ws.pendingVerifier === 'string' && ws.pendingVerifier.length > 0) {
    parts.push(`verifier: ${ws.pendingVerifier}`);
  }
  if (Array.isArray(ws.openHypotheses) && ws.openHypotheses.length > 0) {
    parts.push(`recent: ${ws.openHypotheses.join('; ')}`);
  }
  if (parts.length === 0) return '';
  return `WORKING SET: ${parts.join(' | ')}`;
}

/**
 * Render a CompactionSummary as the structured context message injected in place of the compacted messages.
 */
// @kern-source: compaction:201
export function renderCompactionText(summary: CompactionSummaryPart, cycleCount: number): string {
  return [
    `[Context compacted — ${summary.messagesCompacted} messages total, ${cycleCount} this cycle]`,
    summary.goal ? `GOAL: ${summary.goal}` : '',
    summary.discoveries.length > 0 ? `DISCOVERIES:\n${summary.discoveries.map((d: string) => `  - ${d}`).join('\n')}` : '',
    summary.filesRead.length > 0 ? `FILES READ: ${summary.filesRead.join(', ')}` : '',
    summary.filesModified.length > 0 ? `FILES MODIFIED: ${summary.filesModified.join(', ')}` : '',
    summary.toolsSummary.length > 0 ? `TOOLS USED: ${summary.toolsSummary.join(', ')}` : '',
    summary.decisions.length > 0 ? `DECISIONS:\n${summary.decisions.map((d: string) => `  - ${d}`).join('\n')}` : '',
    summary.progress ? `LATEST PROGRESS: ${summary.progress}` : '',
    renderWorkingSet(summary.workingSet ?? null),
  ].filter(Boolean).join('\n');
}

// @kern-source: compaction:217
export interface SummarizationCaps {
  perMessageChars: number;
  perToolChars: number;
  totalChars: number;
}

/**
 * Bounded plain-text transcript of a message history for the LLM compaction prompt. Caps each message, then enforces the total budget by dropping the OLDEST entries behind an omission marker, so the summary request itself can never overflow the window (the failure mode where compaction breaks exactly when it's needed most).
 */
// @kern-source: compaction:225
export function buildSummarizationContext(messages: CompactMessage[], caps: SummarizationCaps): string {
  const lines: string[] = [];
  for (const m of messages as any[]) {
    if (m.role === 'system') continue;
    let body: string;
    if (typeof m.content === 'string') {
      body = m.content;
    } else if (Array.isArray(m.tool_calls) && m.tool_calls.length > 0) {
      body = `(tool calls: ${m.tool_calls.map((tc: any) => tc?.function?.name ?? tc?.name ?? 'tool').join(', ')})`;
    } else {
      try { body = m.content == null ? '' : JSON.stringify(m.content); } catch { body = String(m.content ?? ''); }
    }
    const cap = m.role === 'tool' ? caps.perToolChars : caps.perMessageChars;
    if (body.length > cap) body = body.slice(0, cap) + ` …[truncated, ${body.length} chars total]`;
    lines.push(`[${m.role}] ${body}`);
  }
  // Enforce the total budget from the END (keep the most recent context).
  let total = 0;
  let firstKept = lines.length;
  for (let i = lines.length - 1; i >= 0; i--) {
    total += lines[i].length + 1;
    if (total > caps.totalChars) break;
    firstKept = i;
  }
  if (firstKept > 0) {
    return `[… ${firstKept} earlier messages omitted from this summary request — already covered by prior compaction notes …]\n${lines.slice(firstKept).join('\n')}`;
  }
  return lines.join('\n');
}

/**
 * The structured compaction prompt (Claude Code-style): explicit sections so the summary preserves what the next turn actually needs — goal, decisions, files, state, next steps.
 */
// @kern-source: compaction:257
export function buildCompactionPrompt(transcript: string): string {
  return `You are compacting an agent conversation so it can continue in the same session with most of the history replaced by your summary. Write a dense, factual briefing with EXACTLY these sections (omit a section only if truly empty):

  GOAL: the user's overall objective, in their terms.
  STATE: what has been accomplished so far and what is in progress right now.
  KEY DECISIONS: decisions made and the reasons, including approaches that were tried and rejected.
  FILES: files read and files modified (full paths), with a phrase on what matters in each.
  DISCOVERIES: important findings, root causes, constraints, gotchas.
  NEXT STEPS: the concrete next actions the conversation was about to take.

  Be specific (paths, names, values). Do not invent anything not in the transcript. No preamble, no closing remarks — output only the briefing.

  TRANSCRIPT:
  ${transcript}`;
}
